  setOrcamento() {
    let idCategoria = this.orcamentosIni.filter(
      (filter) => filter.title == this.item.idOrcamento
    );
    let temp = this.categoriasIni.filter(
      (filter) => filter.id == idCategoria[0].id
    );
    this.item.idCategoria = temp[0].nome;
  }

