  async getPicture() {
    const image = await Camera.getPhoto({
      quality: 100,
      allowEditing: false,
      resultType: CameraResultType.DataUrl,
      source: CameraSource.Photos,
      saveToGallery: false,
    });
    this.item.imagens.push(
      this.sanitizer.bypassSecurityTrustResourceUrl(image && image.dataUrl)
    );
  }

  async imageOptions() {
    const actionSheet = await this.actionSheetController.create({
      header: "Documento",
      cssClass: "my-custom-class",
      buttons: [
        {
          text: "Câmera",
          icon: "camera",
          handler: () => {
            this.takePicture();
          },
        },
        {
          text: "Carregar imagem",
          icon: "image",
          handler: () => {
            this.getPicture();
          },
        },
        {
          text: "Cancelar",
          icon: "close",
          role: "cancel",
        },
      ],
    });
    await actionSheet.present();
  }

  async save() {
    this._translate.get(["T_LOADING"]).subscribe((res: Array<string>) => {
      this.loadingPresent(res);
    });
    let idPagtoAntecipado = [{ id: -1 }];
    let data = {
      idGrupo: this.grupos.filter((filter) => filter.nome == this.item.idGrupo),
      idFormaPag: this.formaPagamentos.filter(
        (filter) => filter.title == this.item.idFormaPagamento
      ),
      idSubCategoria: this.categorias.filter(
        (filter) => filter.nome == this.item.idCategoria
      ),
      idFormaReemb: this.formaReembolsos.filter(
        (filter) => filter.title == this.item.idFormaReembolso
      ),
      idBatch: null,
      idOrcamento: this.orcamentos.filter(
        (filter) => filter.title == this.item.idOrcamento
      ),
      idPagtoAntecipado: idPagtoAntecipado,
      title: this.item.nome,
      data: this.item.data,
    };
      this.dataService.saveDocumentNoImage(data, null).subscribe((values:any) => {
        console.log("doc gravado. Info: " + JSON.stringify(values));
      });
    
  }

  setCCInfo(cc, state, value, isUser) {
    if (isUser) {
      if (!this.ccustoUser[cc].isChecked) {
        this.alertCCPromp(cc, isUser);
      } else {
        if (state) {
          this.ccustoUser[cc].peso = value.peso;
        } else {
          this.ccustoUser[cc].peso = value;
        }
      }
    } else {
      if (!this.ccustoOther[cc].isChecked) {
        this.alertCCPromp(cc, isUser);
      } else {
        if (state) {
          this.ccustoOther[cc].peso = value.peso;
        } else {
          this.ccustoOther[cc].peso = value;
        }
      }
    }
  }

  async alertCCPromp(cc, isUser) {
    const alert = await this.alertController.create({
      cssClass: "ccPeso",
      header: "Insira o peso do centro de custo selecionado:",
      inputs: [
        {
          name: "peso",
          type: "number",
          placeholder: "Insira o peso do centro custo",
        },
      ],
      buttons: [
        {
          text: "Ok",
          handler: (value) => {
            console.log(JSON.stringify(value));
            this.setCCInfo(cc, true, value, isUser);
          },
        },
      ],
    });

    await alert.present();
  }

  async loadingPresent(res) {
    this.isLoading = true;
    return await this.loadingController
      .create({
        message: "A carregar" + "...",
        spinner: "circles",
      })
      .then((a) => {
        a.present().then(() => {
          if (!this.isLoading) {
            a.dismiss();
          }
        });
      });
  }

  async loadingDismiss() {
    this.isLoading = false;
    return await this.loadingController.dismiss();
  }

  async setAlertMessage(res, header, body) {
    const alert = await this.alertController.create({
      cssClass: "alertMessage",
      header: header,
      message: body,
      buttons: ["Ok"],
    });
    await alert.present();
  }

  resetData() {
    this.step = 0;
    this.item = {
      imagens: [],
      nome: "",
      data: new Date().toISOString(),
      idGrupo: "",
      idOrcamento: "",
      idCategoria: "",
      idFormaPagamento: "",
      idFormaReembolso: "",
      idPagtoAntecipado: "",
      fomrBase:""
    };
    this.ccustoUser = this.ccustoIni.filter(
      (filter) => filter.isUser == true
    );
    this.ccustoOther = this.ccustoIni.filter(
      (filter) => filter.isUser == false
    );
  }
